import numpy as np

# Naive Bayes from scratch
class NaiveBayes:
    def fit(self, X, y):
        self.classes = np.unique(y)
        self.priors = {c: np.mean(y == c) for c in self.classes}
        self.means = {c: X[y == c].mean(axis=0) for c in self.classes}
        self.stds = {c: X[y == c].std(axis=0) + 1e-9 for c in self.classes}

    def predict(self, X):
        log_probs = []
        for c in self.classes:
            log_prior = np.log(self.priors[c])
            # Gaussian likelihood (log)
            log_likelihood = -0.5 * np.sum(
                np.log(2*np.pi*self.stds[c]**2) +
                ((X - self.means[c])**2 / self.stds[c]**2), axis=1)
            log_probs.append(log_prior + log_likelihood)
        return self.classes[np.argmax(np.array(log_probs), axis=0)]
